# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = None
    
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            cursorclass=pymysql.cursors.DictCursor
        )
        
        query_params = event.get('queryStringParameters', {}) or {}
        body_params = {}
        
        if event.get('body'):
            try:
                body_params = json.loads(event['body'])
            except:
                body_params = {}
        
        search_params = {**query_params, **body_params}
        
        base_query = "SELECT * FROM products WHERE 1=1"
        conditions = []
        values = []
        
        if search_params.get('product_id'):
            conditions.append("product_id = %s")
            values.append(search_params['product_id'])
        
        if search_params.get('name'):
            conditions.append("name LIKE %s")
            values.append(f"%{search_params['name']}%")
        
        if search_params.get('category'):
            conditions.append("category = %s")
            values.append(search_params['category'])
        
        if search_params.get('min_price'):
            conditions.append("price >= %s")
            values.append(float(search_params['min_price']))
        
        if search_params.get('max_price'):
            conditions.append("price <= %s")
            values.append(float(search_params['max_price']))
        
        if search_params.get('brand'):
            conditions.append("brand = %s")
            values.append(search_params['brand'])
        
        if search_params.get('in_stock'):
            if search_params['in_stock'].lower() in ['true', '1', 'yes']:
                conditions.append("stock_quantity > 0")
        
        if search_params.get('status'):
            conditions.append("status = %s")
            values.append(search_params['status'])
        
        if search_params.get('tags'):
            conditions.append("tags LIKE %s")
            values.append(f"%{search_params['tags']}%")
        
        if search_params.get('description'):
            conditions.append("description LIKE %s")
            values.append(f"%{search_params['description']}%")
        
        if search_params.get('sku'):
            conditions.append("sku = %s")
            values.append(search_params['sku'])
        
        if conditions:
            base_query += " AND " + " AND ".join(conditions)
        
        order_by = search_params.get('order_by', 'product_id')
        allowed_order_fields = ['product_id', 'name', 'price', 'created_at', 'updated_at', 'stock_quantity']
        if order_by not in allowed_order_fields:
            order_by = 'product_id'
        
        order_direction = search_params.get('order_direction', 'ASC').upper()
        if order_direction not in ['ASC', 'DESC']:
            order_direction = 'ASC'
        
        base_query += f" ORDER BY {order_by} {order_direction}"
        
        limit = int(search_params.get('limit', 100))
        if limit > 1000:
            limit = 1000
        if limit < 1:
            limit = 1
        base_query += f" LIMIT {limit}"
        
        offset = int(search_params.get('offset', 0))
        if offset < 0:
            offset = 0
        if offset > 0:
            base_query += f" OFFSET {offset}"
        
        with connection.cursor() as cursor:
            cursor.execute(base_query, values)
            results = cursor.fetchall()
            
            count_query = "SELECT COUNT(*) as total FROM products WHERE 1=1"
            if conditions:
                count_query += " AND " + " AND ".join(conditions)
            
            cursor.execute(count_query, values)
            total_count = cursor.fetchone()['total']
        
        response_body = {
            'success': True,
            'data': results,
            'count': len(results),
            'total': total_count,
            'limit': limit,
            'offset': offset
        }
        
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps(response_body, default=str)
        }
        
    except pymysql.MySQLError as e:
        error_message = str(e)
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': 'Database error',
                'message': error_message
            })
        }
        
    except ValueError as e:
        return {
            'statusCode': 400,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': 'Invalid parameter',
                'message': str(e)
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'success': False,
                'error': 'Internal server error',
                'message': str(e)
            })
        }
        
    finally:
        if connection:
            connection.close()